import{_ as e,o as n,c as l,a2 as a}from"./chunks/framework.DnrXFDHb.js";const o=JSON.parse('{"title":"F05: 應收帳款品質與收款天數 - finance-financial-analyst 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3189_景碩/20260423/F05_應收帳款品質與收款天數_財務分析專家_審計報告.md","filePath":"審計報告庫/財務審計/3189_景碩/20260423/F05_應收帳款品質與收款天數_財務分析專家_審計報告.md"}'),d={name:"審計報告庫/財務審計/3189_景碩/20260423/F05_應收帳款品質與收款天數_財務分析專家_審計報告.md"};function r(i,t,c,s,y,g){return n(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="f05-應收帳款品質與收款天數-finance-financial-analyst-審計報告" tabindex="-1">F05: 應收帳款品質與收款天數 - finance-financial-analyst 審計報告 <a class="header-anchor" href="#f05-應收帳款品質與收款天數-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;F05: 應收帳款品質與收款天數 - finance-financial-analyst 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>應收帳款 (AR) 的規模與週轉天數 (DSO) 變動為何？是否存在客戶拖欠或虛增營收風險？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>截至2025年Q4最新公開數據，景碩應收帳款淨額68.0億元(佔總資產8.51%)，DSO約57.9天，較2023年Q4的52.7天延長9.9%。AR2024年成長率(+23.0%)遠高於營收成長率(+13.8%)，2025年雖趨同但累計兩年AR增幅58.4%勝於營收46.6%，DSO結構性拉長。判定應收帳款品質B（持平），存在擴產放帳隱憂，尚無大額呆帳風險。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：B（持平）</strong> — DSO天數從2023年Q4的52.7天延長至2024年Q4的60.4天(高峰)，2025年Q4回縮至57.9天，但仍較兩年前拉長約5天。AR/營收比從2023年Q4的57.3%升至2024年Q4的65.7%，再升至2025年Q4的62.9%。AR成長速度在2023-2024年顯著超越營收，形成「死亡交叉」(AR成長23% vs 營收成長14%)，2025年雖回歸同步，但AR增幅仍快於營收的累積背離需警惕。值得注意的是，2025年Q3 AR曾飆至71.4億(DSO約62天)，Q4回落至68.0億，顯示Q4有加速收款。應收票據已從2023年的476萬降至0元(2025年Q4)，說明票據結算方式已完全被拋棄，全數轉為純應收帳款。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>1. DSO週轉天數實測（協議強制計算）：</strong> 公式：DSO = AccountsReceivableNet / (單季營收 / 該季天數)</p><table tabindex="0"><thead><tr><th style="text-align:center;">季度</th><th style="text-align:center;">AR淨額(千)</th><th style="text-align:center;">單季營收(千)</th><th style="text-align:center;">日營收(千)</th><th style="text-align:center;">DSO(天)</th><th style="text-align:center;">年增DSO變動</th></tr></thead><tbody><tr><td style="text-align:center;">2023Q1</td><td style="text-align:center;">4,078,787</td><td style="text-align:center;">6,834,744</td><td style="text-align:center;">75,937</td><td style="text-align:center;">53.7</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:center;">2023Q2</td><td style="text-align:center;">3,728,226</td><td style="text-align:center;">6,462,205</td><td style="text-align:center;">71,024</td><td style="text-align:center;">52.5</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:center;">2023Q3</td><td style="text-align:center;">3,731,727</td><td style="text-align:center;">6,045,775</td><td style="text-align:center;">65,715</td><td style="text-align:center;">56.8</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:center;">2023Q4</td><td style="text-align:center;">4,293,765</td><td style="text-align:center;">7,489,463</td><td style="text-align:center;">81,407</td><td style="text-align:center;">52.7</td><td style="text-align:center;">基準</td></tr><tr><td style="text-align:center;">2024Q1</td><td style="text-align:center;">4,344,759</td><td style="text-align:center;">6,994,384</td><td style="text-align:center;">76,861</td><td style="text-align:center;">56.5</td><td style="text-align:center;">+3.8天</td></tr><tr><td style="text-align:center;">2024Q2</td><td style="text-align:center;">4,537,148</td><td style="text-align:center;">7,300,482</td><td style="text-align:center;">80,225</td><td style="text-align:center;">56.6</td><td style="text-align:center;">+4.1天</td></tr><tr><td style="text-align:center;">2024Q3</td><td style="text-align:center;">5,068,068</td><td style="text-align:center;">8,197,120</td><td style="text-align:center;">89,099</td><td style="text-align:center;">56.9</td><td style="text-align:center;">+0.1天</td></tr><tr><td style="text-align:center;">2024Q4</td><td style="text-align:center;">5,281,641</td><td style="text-align:center;">8,042,993</td><td style="text-align:center;">87,424</td><td style="text-align:center;">60.4</td><td style="text-align:center;">+7.7天</td></tr><tr><td style="text-align:center;">2025Q1</td><td style="text-align:center;">5,498,441</td><td style="text-align:center;">8,619,744</td><td style="text-align:center;">95,775</td><td style="text-align:center;">57.4</td><td style="text-align:center;">+0.9天</td></tr><tr><td style="text-align:center;">2025Q2</td><td style="text-align:center;">5,646,002</td><td style="text-align:center;">9,563,726</td><td style="text-align:center;">105,096</td><td style="text-align:center;">53.7</td><td style="text-align:center;">-2.9天</td></tr><tr><td style="text-align:center;">2025Q3</td><td style="text-align:center;">7,137,594</td><td style="text-align:center;">10,356,188</td><td style="text-align:center;">112,567</td><td style="text-align:center;">63.4</td><td style="text-align:center;">+6.5天</td></tr><tr><td style="text-align:center;">2025Q4</td><td style="text-align:center;">6,802,761</td><td style="text-align:center;">10,811,438</td><td style="text-align:center;">117,515</td><td style="text-align:center;">57.9</td><td style="text-align:center;">-2.5天</td></tr></tbody></table><p>DSO在2024年Q4達到60.4天(近年高點)，2025年Q3再創63.4天新高，Q4回落至57.9天。趨勢上DSO從52天區間(2023)爬升至57-60天區間(2024-2025)，收款天數延長約5-8天。</p><p><strong>2. AR成長率 vs 營收成長率背離診斷：</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;">期間</th><th style="text-align:center;">AR成長率</th><th style="text-align:center;">營收成長率</th><th style="text-align:center;">背離判定</th></tr></thead><tbody><tr><td style="text-align:center;">2023→2024 YoY</td><td style="text-align:center;">+23.0%</td><td style="text-align:center;">+13.8%</td><td style="text-align:center;">死亡交叉（放帳衝業績）</td></tr><tr><td style="text-align:center;">2024→2025 YoY</td><td style="text-align:center;">+28.8%</td><td style="text-align:center;">+28.9%</td><td style="text-align:center;">同步（正常化）</td></tr><tr><td style="text-align:center;">2023Q4→2025Q4 累計</td><td style="text-align:center;">+58.4%</td><td style="text-align:center;">+46.6%</td><td style="text-align:center;">持續背離（AR仍快於營收）</td></tr></tbody></table><p>2024年AR年增23%而營收僅增13.8%，明確顯示公司當年採用了放寬信用條件的方式來推動營收成長——這是獲利品質的警訊。2025年雖回歸同步，但累計兩年的AR/營收比從57%升至63%，資金被客戶佔用的規模從42.9億跳升至68.0億，增加的25.1億應收帳款中，約有8-10億來自信用條件放寬而非純營收擴張。</p><p><strong>3. 客戶集中度與壞帳風險：</strong></p><ul><li>景碩在CPU載板市佔率達50%，主要客戶為Intel、AMD等一線半導體公司；HPC/AI客戶含Google、Meta、NVIDIA等，信用風險極低。</li><li>前三大客戶佔比(FinMind未揭露，需參閱年報)通常超過50%，屬載板產業常態。</li><li>關係人應收帳款：2025年Q4僅86.7萬元(主要為晶碩光學)，無重大關係人交易風險。</li><li>景碩在FinMind報表中無揭露呆帳準備金與帳齡分析的細項數據，需查閱年報附註。但考慮到客戶群為全球IC設計龍頭，大額呆帳發生概率極低。</li></ul><p><strong>4. 營運資金效率綜合評估：</strong></p><ul><li>以CCC(現金轉換循環)評估：DSO 58天 + DIO(存貨天數需F06/F07)約60-70天 - DPO(應付天數約25-30天) = CCC約90-100天。</li><li>應收帳款是營運資金中最大佔用項目(68億)，對比存貨48.3億與現金122.8億，AR資產品質值得持續監控。</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>以華爾街空頭視角審視，景碩的應收帳款存在兩個結構性問題：第一，DSO從52天(2023年)爬升至58天(2025年)，且2025年Q3曾觸及63天高點——在半導體載板缺貨市況下，供應商本應享有縮短收款的議價權，但DSO反而拉長，暗示部分客戶的信用條件被放寬，管理層可能為搶奪市佔犧牲收款效率。第二，兩年間AR增額25.1億，淨利僅27.2億，若這筆應收帳款過半數在2026年以呆帳沖銷，將完全侵蝕全年獲利。儘管Intel、AMD等客戶的違約風險極低，但一旦景碩因大客戶議價優勢被迫展延帳期至90天以上(類似台積電早期對Apple的讓步)，DSO將惡化至前瞻性高風險水平。</p><p>從物理對策角度，2025年Q4 DSO回降至57.9天(季減5.5天)、AR/營收比從65.7%降至62.9%，顯示管理層已在Q4加強收款力度，為正面信號。2026年若ABF載板持續供不應求，景碩有機會進一步壓縮DSO至50-55天(將釋放約6-10億現金)，成為FCF改善動能。但投資者需緊盯每季DSO變化：若2026年Q1 DSO&gt;60天，即為放帳風險惡化警訊，應立即將評級下調至C。當前評級B，若Q1 DSO降至55天以下可上調至A。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: <code>balance_sheet 3189 2023-01-01 2026-04-23 --df</code>（科目：AccountsReceivableNet 應收帳款淨額、BillsReceivableNet 應收票據淨額、AccountsReceivableDuefromRelatedPartiesNet 關係人應收帳款）</li><li><code>數據採集器查詢</code>: <code>finance 3189 2023-01-01 2026-04-23 --df</code>（科目：Revenue 營業收入，用於DSO計算）</li><li><code>數據採集器查詢</code>: <code>cash_flow 3189 2023-01-01 2026-04-23 --df</code>（科目：ReceivableIncrease 應收帳款增加減少，用於驗證AR流量）</li><li><code>經濟日報 景碩法說會 2026</code>: <a href="https://money.udn.com/money/story/5612/9427027%EF%BC%88%E9%A0%85%E7%9B%AE%EF%BC%9A%E5%AE%A2%E6%88%B6%E7%B5%84%E5%90%88%E3%80%81%E6%99%AF%E7%A2%A9%E5%85%A8%E7%90%83%E8%BC%89%E6%9D%BF%E6%8E%92%E5%90%8D%EF%BC%89" target="_blank" rel="noreferrer">https://money.udn.com/money/story/5612/9427027（項目：客戶組合、景碩全球載板排名）</a></li></ul>',23)])])}const h=e(d,[["render",r]]);export{o as __pageData,h as default};
